SELECT COUNT(DISTINCT C.ID) AS QUANTIDADE FROM CALC_HORA_AULA_MEDIA C JOIN SERVIDOR S ON S.PK_SIAPE = C.SIAPE WHERE LOWER(S.GENERO) = LOWER('feminino') AND LOWER(C.AREA_INGRESSO) LIKE LOWER('%biologia geral%') AND LOWER(C.SIGLA_CAMPUS) = LOWER('for') AND C.ANO >= ((CAST(strftime('%Y', 'now') AS INTEGER)) - 4) AND EXISTS (SELECT 1 FROM CURSO CUR WHERE LOWER(CUR.SIGLA) = LOWER(C.SIGLA_CURSO) AND LOWER(CUR.NIVEL) = LOWER('superior'))